import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class InputHandlerServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>XSS Protection Example</title></head>");
        out.println("<body>");

        // Sanitize user input to prevent XSS
        String sanitizedInput = sanitizeInput(userInput);

        out.println("User Input: " + sanitizedInput);

        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String userInput) {
        // Replace potentially harmful characters with their HTML entity equivalents
        return userInput.replaceAll("&", "&amp;")
                        .replaceAll("<", "&lt;")
                        .replaceAll(">", "&gt;")
                        .replaceAll("\"", "&quot;")
                        .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
